#include <bits/stdc++.h>
using namespace std;

int main() {
    int t, n, x, y;
    cin >> t;
    while (t--) {
        cin >> n >> x >> y;
        getchar();
        int cnts = 0, cntf = 0;
        for (int i = 0; i < n; i++) {
            char c;
            c = getchar();
            if (c == 'S') cnts++;
            else cntf++;
        }
        double a = double(x - cntf);
        double b = double(y - cnts);
        cout << int(ceil(a / b)) << endl;
    }
    return 0;
}
